  deleteCard as apiDeleteCard,
  createComment,
} from '../api/client.js'

// ---------------------------------------------------------------------------
// Module-level helpers
// ---------------------------------------------------------------------------

/**
 * Map API column value → state key.
 * 'in-progress' (hyphen) → 'in_progress' (underscore); others pass through.
 * @param {string} col
 * @returns {string}
 */
export function columnToKey(col) {
  return col === 'in-progress' ? 'in_progress' : col
}

/**
 * Group a flat array of cards into the board state shape, sorted by position.
 * @param {import('../api/client.js').Card[]} cards
 * @returns {{ ready: Card[], in_progress: Card[], done: Card[] }}
 */
function groupCards(cards) {
  const board = { ready: [], in_progress: [], done: [] }
  for (const card of cards) {
    const key = columnToKey(card.column)
    if (key in board) board[key].push(card)
  }
  for (const key of Object.keys(board)) {
    board[key].sort((a, b) => a.position - b.position)
  }
  return board
}

const EMPTY_BOARD = { ready: [], in_progress: [], done: [] }

// Temp-ID counter for optimistic records (module-level so it's stable across renders)
let _tempId = 0
function nextTempId() {
  return '__temp_' + (++_tempId)
}

// ---------------------------------------------------------------------------
// useBoard hook
// ---------------------------------------------------------------------------

/**
 * Manages board state: cards grouped by column, loading, and error.
 *
 * Column convention
 *   - State keys:  ready | in_progress | done  (underscore)
 *   - API values:  ready | in-progress  | done  (hyphen for in-progress)
 *   - All hook functions that accept a column name expect the API format.
 *   - Each card's .column field retains the API format.
 *
 * @returns {{
 *   cards: { ready: Card[], in_progress: Card[], done: Card[] },
 *   loading: boolean,
 *   error: string|null,
 *   createCard: (data: object) => Promise<Card>,
 *   updateCard: (id: string, data: object) => Promise<Card>,
 *   deleteCard: (id: string) => Promise<void>,
 *   moveCard: (id: string, targetColumn: string, position?: number) => Promise<Card>,
 *   addComment: (cardId: string, data: object) => Promise<Comment>,
 * }}
 */
export function useBoard() {
  const [cards, setCards] = useState(EMPTY_BOARD)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)

  // Counter for concurrent in-flight operations so loading stays true
  // until the LAST operation finishes.
  const pendingRef = useRef(0)

  // Ref that always holds the latest cards state so we can read it
  // synchronously (functional updaters are called lazily by React, which
  // would leave a rollback variable null if the API rejects as a microtask
  // before the updater runs).
  const cardsRef = useRef(EMPTY_BOARD)

  /**
   * Apply a state update eagerly: compute the next value synchronously from
   * cardsRef.current, update the ref, then call setCards with the plain
   * computed value (not a function) so React picks it up on the next render.
   */
  function applyCards(updater) {
    const next = typeof updater === 'function' ? updater(cardsRef.current) : updater
    cardsRef.current = next
    setCards(next)
  }

  function beginOp() { pendingRef.current++; setLoading(true) }
  function endOp()   { if (--pendingRef.current === 0) setLoading(false) }

  // -------------------------------------------------------------------------
  // Initial data load
  // -------------------------------------------------------------------------

  useEffect(() => {
    let cancelled = false
    setError(null)
    beginOp()

    fetchCards()
      .then(data => {
        if (cancelled) return
        applyCards(groupCards(data))
        endOp()
      })
      .catch(err => {
        if (cancelled) return
        setError(err.message)
        endOp()
      })

    return () => { cancelled = true }
  }, [])

  // -------------------------------------------------------------------------
  // createCard — temp-ID optimistic pattern
  // -------------------------------------------------------------------------

  const createCard = useCallback(async (data) => {
    const tempId = nextTempId()
    const col = data.column ?? 'ready'
    const key = columnToKey(col)

    const optimisticCard = {
      id: tempId,
      title: data.title,
      assignee: data.assignee ?? null,
      column: col,
      position: Infinity,
      description: data.description ?? null,
      created_at: Date.now(),
      comments: [],
    }

    applyCards(prev => ({ ...prev, [key]: [...prev[key], optimisticCard] }))
    beginOp()

    try {
      const created = await apiCreateCard(data)
      const createdKey = columnToKey(created.column)
      applyCards(prev => {
        const next = { ...prev }
        // Remove the temp card from whichever column it was placed in
        next[key] = next[key].filter(c => c.id !== tempId)
        // Insert the server card into the column the server assigned
        next[createdKey] = [...next[createdKey], created]
          .sort((a, b) => a.position - b.position)
        return next
      })
      return created
    } catch (err) {
      applyCards(prev => ({
        ...prev,
        [key]: prev[key].filter(c => c.id !== tempId),
      }))
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // updateCard — rollback pattern (column changes ignored; use moveCard)
  // -------------------------------------------------------------------------

  const updateCard = useCallback(async (id, data) => {
    // Strip column — column changes must go through moveCard
    const safeData = { ...data }
    delete safeData.column

    // Capture rollback synchronously from the ref (not inside a lazy updater)
    const rollback = cardsRef.current
    applyCards(prev => {
      const next = {}
      for (const [k, col] of Object.entries(prev)) {
        next[k] = col.map(c => c.id === id ? { ...c, ...safeData } : c)
      }
      return next
    })
    beginOp()

    try {
      const updated = await apiUpdateCard(id, safeData)
      applyCards(prev => {
        const next = {}
        for (const [k, col] of Object.entries(prev)) {
          next[k] = col.map(c => c.id === id ? updated : c)
        }
        return next
      })
      return updated
    } catch (err) {
      applyCards(rollback)
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // deleteCard — rollback pattern
  // -------------------------------------------------------------------------

  const deleteCard = useCallback(async (id) => {
    // Capture rollback synchronously from the ref
    const rollback = cardsRef.current
    applyCards(prev => {
      const next = {}
      for (const [k, col] of Object.entries(prev)) {
        next[k] = col.filter(c => c.id !== id)
      }
      return next
    })
    beginOp()

    try {
      await apiDeleteCard(id)
    } catch (err) {
      applyCards(rollback)
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // moveCard — rollback pattern
  // targetColumn must be in API format ('ready' | 'in-progress' | 'done')
  // -------------------------------------------------------------------------

  const moveCard = useCallback(async (id, targetColumn, position) => {
    const targetKey = columnToKey(targetColumn)

    // Capture rollback synchronously from the ref
    const rollback = cardsRef.current
    applyCards(prev => {
      let cardToMove = null
      const next = {}

      for (const [k, col] of Object.entries(prev)) {
        const idx = col.findIndex(c => c.id === id)
        if (idx !== -1) {
          cardToMove = col[idx]
          next[k] = col.filter(c => c.id !== id)
        } else {
          next[k] = col
        }
      }

      if (!cardToMove) return prev

      const movedCard = {
        ...cardToMove,
        column: targetColumn,
        ...(position !== undefined ? { position } : {}),
      }
      next[targetKey] = [...next[targetKey], movedCard]
        .sort((a, b) => a.position - b.position)
      return next
    })
    beginOp()

    try {
      const payload = { column: targetColumn }
      if (position !== undefined) payload.position = position
      const updated = await apiUpdateCard(id, payload)
      const updatedKey = columnToKey(updated.column)
      applyCards(prev => {
        const next = {}
        for (const [k, col] of Object.entries(prev)) {
          next[k] = col.filter(c => c.id !== id)
        }
        next[updatedKey] = [...next[updatedKey], updated]
          .sort((a, b) => a.position - b.position)
        return next
      })
      return updated
    } catch (err) {
      applyCards(rollback)
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // addComment — temp-ID optimistic pattern
  // -------------------------------------------------------------------------

  const addComment = useCallback(async (cardId, data) => {
    const tempId = nextTempId()
    const optimisticComment = {
      id: tempId,
      card_id: cardId,
      author: data.author,
      content: data.content,
      created_at: Date.now(),
    }

    applyCards(prev => {
      const next = {}
      for (const [k, col] of Object.entries(prev)) {
        next[k] = col.map(c =>
          c.id === cardId
            ? { ...c, comments: [...c.comments, optimisticComment] }
            : c
        )
      }
      return next
    })
    beginOp()

    try {
      const comment = await createComment(cardId, data)
      applyCards(prev => {
        const next = {}
        for (const [k, col] of Object.entries(prev)) {
          next[k] = col.map(c =>
            c.id === cardId
              ? {
                  ...c,
                  comments: c.comments
                    .filter(cm => cm.id !== tempId)
                    .concat(comment),
                }
              : c
          )
        }
        return next
      })
      return comment
    } catch (err) {
      applyCards(prev => {
        const next = {}
        for (const [k, col] of Object.entries(prev)) {
          next[k] = col.map(c =>
            c.id === cardId
              ? { ...c, comments: c.comments.filter(cm => cm.id !== tempId) }
              : c
          )
        }
        return next
      })
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // Public interface
  // -------------------------------------------------------------------------

  return {
    cards,
    loading,
    error,
    createCard,
    updateCard,
    deleteCard,
    moveCard,
    addComment,
  }
}

import { useState } from 'react'
import { useBoard } from '../../hooks/useBoard.js'
import Column from './Column.jsx'
import CardModal from './CardModal.jsx'
import './Board.css'

export default function Board() {
  const { cards, loading, error, updateCard, deleteCard } = useBoard()
  const [selectedCardId, setSelectedCardId] = useState(null)
  const allCards = [...cards.ready, ...cards.in_progress, ...cards.done]
  const selectedCard = selectedCardId ? (allCards.find(c => c.id === selectedCardId) ?? null) : null

  if (loading) return <div className="board-loading" aria-label="Loading">Loading…</div>
  if (error) return <div className="board-error" role="alert">{error}</div>

  return (
    <div className="board">
      <Column title="Ready" cards={cards.ready} onCardClick={(card) => setSelectedCardId(card.id)} />
      <Column title="In Progress" cards={cards.in_progress} onCardClick={(card) => setSelectedCardId(card.id)} />
      <Column title="Done" cards={cards.done} onCardClick={(card) => setSelectedCardId(card.id)} />
      {selectedCard && (
        <CardModal
          card={selectedCard}
          onClose={() => setSelectedCardId(null)}
          onUpdate={updateCard}
          onDelete={deleteCard}
        />
      )}
    </div>
  )
}

import { render, screen, fireEvent, within } from '@testing-library/react'
import { describe, it, expect, vi, beforeEach } from 'vitest'
import { useBoard } from '../../hooks/useBoard.js'
import Board from './Board.jsx'

vi.mock('../../hooks/useBoard.js', () => ({ useBoard: vi.fn() }))

const MOCK_CARD = {
  id: 'c1',
  title: 'Test Card',
  assignee: 'Alice',
  description: 'A description',
  column: 'ready',
  position: 1,
  created_at: Date.now(),
  comments: [],
}

const DEFAULT_STATE = {
  cards: { ready: [], in_progress: [], done: [] },
  loading: false,
  error: null,
  createCard: vi.fn(),
  updateCard: vi.fn(),
  deleteCard: vi.fn(),
  moveCard: vi.fn(),
  addComment: vi.fn(),
}

beforeEach(() => {
  useBoard.mockReturnValue(DEFAULT_STATE)
})

describe('Board', () => {
  it('renders three column regions', () => {
    render(<Board />)
    expect(screen.getAllByRole('region')).toHaveLength(3)
  })

  it('renders Ready column heading', () => {
    render(<Board />)
    expect(screen.getByRole('heading', { name: 'Ready' })).toBeInTheDocument()
  })

  it('renders In Progress column heading', () => {
    render(<Board />)
    expect(screen.getByRole('heading', { name: 'In Progress' })).toBeInTheDocument()
  })

  it('renders Done column heading', () => {
    render(<Board />)
    expect(screen.getByRole('heading', { name: 'Done' })).toBeInTheDocument()
  })

  it('shows loading indicator when loading is true', () => {
    useBoard.mockReturnValue({ ...DEFAULT_STATE, loading: true })
    render(<Board />)
    expect(screen.getByLabelText('Loading')).toBeInTheDocument()
    expect(screen.queryAllByRole('region')).toHaveLength(0)
  })

  it('shows error banner when error is set', () => {
    useBoard.mockReturnValue({ ...DEFAULT_STATE, error: 'fetch failed' })
    render(<Board />)
    expect(screen.getByRole('alert')).toHaveTextContent('fetch failed')
  })

  it('passes ready cards to Ready column', () => {
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [MOCK_CARD], in_progress: [], done: [] },
    })
    render(<Board />)
    expect(
      within(screen.getByRole('region', { name: 'Ready' })).getByText('Test Card')
    ).toBeInTheDocument()
  })

  it('passes in_progress cards to In Progress column', () => {
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [], in_progress: [{ ...MOCK_CARD, id: 'c2', column: 'in-progress' }], done: [] },
    })
    render(<Board />)
    expect(
      within(screen.getByRole('region', { name: 'In Progress' })).getByText('Test Card')
    ).toBeInTheDocument()
  })

  it('passes done cards to Done column', () => {
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [], in_progress: [], done: [{ ...MOCK_CARD, id: 'c3', column: 'done' }] },
    })
    render(<Board />)
    expect(
      within(screen.getByRole('region', { name: 'Done' })).getByText('Test Card')
    ).toBeInTheDocument()
  })

  it('opens modal when a card is clicked', () => {
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [MOCK_CARD], in_progress: [], done: [] },
    })
    render(<Board />)
    fireEvent.click(screen.getByRole('button', { name: 'Test Card' }))
    expect(screen.getByRole('dialog')).toBeInTheDocument()
  })

  it('closes modal when close button is clicked', () => {
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [MOCK_CARD], in_progress: [], done: [] },
    })
    render(<Board />)
    fireEvent.click(screen.getByRole('button', { name: 'Test Card' }))
    fireEvent.click(screen.getByRole('button', { name: /close/i }))
    expect(screen.queryByRole('dialog')).toBeNull()
  })

  it('modal reflects updated card data when useBoard cards state changes', () => {
    const card = { ...MOCK_CARD, title: 'Old Title' }
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [card], in_progress: [], done: [] },
    })
    const { rerender } = render(<Board />)
    fireEvent.click(screen.getByRole('button', { name: 'Old Title' }))
    expect(screen.getByRole('dialog')).toHaveTextContent('Old Title')

    // Simulate useBoard updating the card in place (e.g. after updateCard resolves)
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [{ ...card, title: 'New Title' }], in_progress: [], done: [] },
    })
    rerender(<Board />)
    expect(screen.getByRole('dialog')).toHaveTextContent('New Title')
  })

  it('modal closes automatically when selected card is removed from cards state', () => {
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [MOCK_CARD], in_progress: [], done: [] },
    })
    const { rerender } = render(<Board />)
    fireEvent.click(screen.getByRole('button', { name: 'Test Card' }))
    expect(screen.getByRole('dialog')).toBeInTheDocument()

    // Simulate card being deleted from state
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [], in_progress: [], done: [] },
    })
    rerender(<Board />)
    expect(screen.queryByRole('dialog')).toBeNull()
  })
})

/**
 * API client for the Kanban board REST API.
 * All functions use relative URLs so Vite's dev proxy (/api → localhost:3001)
 * and same-origin production serving both work without configuration.
 */

// ---------------------------------------------------------------------------
// Type definitions
// ---------------------------------------------------------------------------

/**
 * @typedef {Object} Card
 * @property {string} id
 * @property {string} title
 * @property {string|null} assignee
 * @property {string} column - e.g. 'ready', 'in-progress', 'done'
 * @property {number} position
 * @property {string|null} description
 * @property {number} created_at - Unix ms timestamp
 * @property {Comment[]} comments
 */

/**
 * @typedef {Object} Comment
 * @property {string} id
 * @property {string} card_id
 * @property {string} author
 * @property {string} content
 * @property {number} created_at
 */

// ---------------------------------------------------------------------------
// ApiError
// ---------------------------------------------------------------------------

export class ApiError extends Error {
  /**
   * @param {string} msg
   * @param {number} status  HTTP status code, or 0 for network-level failures
   * @param {*} data         Parsed error response body, or null
   */
  constructor(msg, status, data) {
    super(msg)
    this.name = 'ApiError'
    this.status = status
    this.data = data
  }
}

// ---------------------------------------------------------------------------
// Internal fetch helper
// ---------------------------------------------------------------------------

async function apiFetch(path, options = {}) {
  const headers = {}
  if (options.body !== undefined) headers['Content-Type'] = 'application/json'

  let response
  try {
    response = await fetch(path, { ...options, headers: { ...headers, ...options.headers } })
  } catch (err) {
    throw new ApiError(`Network error: ${err.message}`, 0, null)
  }

  if (!response.ok) {
    let errorData = null
    try { errorData = await response.json() } catch { /* ignore */ }
    const message = errorData?.error ?? `HTTP error ${response.status}`
    throw new ApiError(message, response.status, errorData)
  }

  if (response.status === 204 || response.headers.get('content-length') === '0') {
    return null
  }

  try {
    return await response.json()
  } catch (err) {
    throw new ApiError(`Failed to parse response: ${err.message}`, response.status, null)
  }
}

// ---------------------------------------------------------------------------
// Public API functions
// ---------------------------------------------------------------------------

/**
 * Fetch all cards with their nested comments.
 * @returns {Promise<Card[]>}
 * @throws {ApiError} on network or HTTP error
 * @example
 * const cards = await fetchCards()
 * console.log(cards[0].title)
 */
export async function fetchCards() {
  return apiFetch('/api/cards')
}

/**
 * Create a new card.
 * @param {{ title: string, assignee?: string, column?: string, description?: string }} data
 * @returns {Promise<Card>}
 * @throws {ApiError} on network or HTTP error
 * @example
 * const card = await createCard({ title: 'Fix bug', assignee: 'Alice' })
 * console.log(card.id)
 */
export async function createCard(data) {
  return apiFetch('/api/cards', { method: 'POST', body: JSON.stringify(data) })
}

/**
 * Partially update an existing card.
 * @param {string} id
 * @param {{ title?: string, assignee?: string, column?: string, description?: string, position?: number }} data
 * @returns {Promise<Card>}
 * @throws {ApiError} on network or HTTP error
 * @example
 * const updated = await updateCard('abc-123', { column: 'done' })
 */
export async function updateCard(id, data) {
  return apiFetch(`/api/cards/${id}`, { method: 'PATCH', body: JSON.stringify(data) })
}

/**
 * Delete a card and all its comments.
 * @param {string} id
 * @returns {Promise<null>}
 * @throws {ApiError} on network or HTTP error
 * @example
 * await deleteCard('abc-123')
 */
export async function deleteCard(id) {
  return apiFetch(`/api/cards/${id}`, { method: 'DELETE' })
}

/**
 * Add a comment to a card.
 * @param {string} cardId
 * @param {{ author: string, content: string }} data
 * @returns {Promise<Comment>}
 * @throws {ApiError} on network or HTTP error
 * @example
 * const comment = await createComment('abc-123', { author: 'Bob', content: 'Looks good!' })
 */
export async function createComment(cardId, data) {
  return apiFetch(`/api/cards/${cardId}/comments`, { method: 'POST', body: JSON.stringify(data) })
}

