                <time className="comment-time" dateTime={new Date(cm.created_at).toISOString()}>
                  {formatRelativeTime(cm.created_at)}
                </time>
              </div>
              <p className="comment-content">{cm.content}</p>
            </li>
          ))}
        </ul>
      )}
