    <div className="modal-overlay" onClick={onClose}>
      <div
        className="modal-content"
        role="dialog"
        aria-modal="true"
        aria-label={card.title}
        onClick={e => e.stopPropagation()}
      >
        {/* 1. Close button */}
        <button className="modal-close" onClick={onClose} aria-label="Close">
