.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  animation: modal-fade-in 150ms ease;
}

@keyframes modal-fade-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

.modal-content {
  background: #fff;
  border-radius: 8px;
  padding: 1.5rem;
  max-width: 480px;
  width: 90%;
  position: relative;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
  animation: modal-slide-in 150ms ease;
  max-height: 90vh;
  overflow-y: auto;
}

@keyframes modal-slide-in {
  from { transform: translateY(12px); }
  to   { transform: translateY(0); }
}

.modal-close {
  position: absolute;
  top: 0.75rem;
  right: 0.75rem;
  background: none;
  border: none;
  cursor: pointer;
  font-size: 1.1rem;
  color: #666;
}

.modal-close:hover {
  color: #1a1a2e;
}

.modal-title {
  font-size: 1.2rem;
  font-weight: 700;
  margin-bottom: 0.75rem;
  color: #1a1a2e;
}

.modal-assignee {
  font-size: 0.875rem;
